 1	import * as React from 'react';
 2	
 3	import {
 4	  k8sCreate,
 5	  K8sModel,
 6	  K8sResourceCommon,
 7	  k8sUpdate,
 8	} from '@openshift-console/dynamic-plugin-sdk';
 9	import { useTranslation } from 'react-i18next';
10	import { Button, AlertVariant, Alert, AlertGroup } from '@patternfly/react-core';
11	import { History } from 'history';
12	
13	interface GenericPolicyForm {
14	  model: K8sModel;
15	  resource: K8sResourceCommon;
16	  policyType: string;
17	  history: History;
18	  validation: boolean;
19	}
20	
21	const KuadrantCreateUpdate: React.FC<GenericPolicyForm> = ({
22	  model,
23	  resource,
24	  policyType,
25	  history,
26	  validation,
27	}) => {
28	  const { t } = useTranslation('plugin__kuadrant-console-plugin');
29	  const [errorAlertMsg, setErrorAlertMsg] = React.useState('');
30	  const update = !!resource.metadata.creationTimestamp;
31	
32	  const handleCreateUpdate = async () => {
33	    if (!validation) return; // Early return if form is not valid
34	    setErrorAlertMsg('');
35	
36	    try {
37	      if (update == true) {
38	        const response = await k8sUpdate({
39	          model: model,
40	          data: resource,
41	        });
42	        console.log(`${policyType} updated successfully:`, response);
43	        history.push(`/kuadrant/all-namespaces/policies/${policyType}`);
44	      } else {
45	        const response = await k8sCreate({
46	          model: model,
47	          data: resource,
48	        });
49	        console.log(`${policyType} created successfully:`, response);
50	        history.push(`/kuadrant/all-namespaces/policies/${policyType}`);
51	      }
52	    } catch (error) {
53	      if (update == true) {
54	        console.error(t(`Cannot update ${policyType}`, error));
55	        setErrorAlertMsg(error.message);
56	      }
57	      {
58	        console.error(t(`Cannot create ${policyType}`, error));
59	        setErrorAlertMsg(error.message);
60	      }
61	    }
62	  };
63	  return (
64	    <>
65	      {errorAlertMsg != '' && (
66	        <AlertGroup className="kuadrant-alert-group">
67	          <Alert title={t(`Error creating ${policyType}`)} variant={AlertVariant.danger} isInline>
68	            {errorAlertMsg}
69	          </Alert>
70	        </AlertGroup>
71	      )}
72	      <Button onClick={handleCreateUpdate} isDisabled={!validation}>
73	        {update ? t(`Save`) : t(`Create`)}
74	      </Button>
75	    </>
76	  );
77	};
78	export default KuadrantCreateUpdate;

